
package com.example.taxgap.service; import com.example.taxgap.domain.entity.ExceptionRecord; import com.example.taxgap.domain.enums.Severity; import com.example.taxgap.repository.ExceptionRecordRepository; import org.springframework.stereotype.Service; import java.util.List;
@Service public class ExceptionService { private final ExceptionRecordRepository repo; public ExceptionService(ExceptionRecordRepository repo){this.repo=repo;} public ExceptionRecord create(String txnId, String customerId, String ruleName, Severity severity, String message){ ExceptionRecord rec=new ExceptionRecord(); rec.setTransactionId(txnId); rec.setCustomerId(customerId); rec.setRuleName(ruleName); rec.setSeverity(severity); rec.setMessage(message); return repo.save(rec);} public List<ExceptionRecord> getAll(String customerId, String severity, String ruleName){ if(customerId!=null && !customerId.isBlank()) return repo.findByCustomerId(customerId); if(severity!=null && !severity.isBlank()) return repo.findBySeverity(Severity.valueOf(severity)); if(ruleName!=null && !ruleName.isBlank()) return repo.findByRuleName(ruleName); return repo.findAll(); } }
